-- Mathisle Tree Import
-- Auto-generated from data/mathisle_250904.csv
-- Run after 19-mathisle-seed-data.sql

SET search_path TO trees, shared, extensions, public;

-- Use a DO block to handle dynamic location ID and skip if already imported
DO $$
DECLARE
    loc_id INTEGER;
    var_id INTEGER := 1; -- 'original' variant type
    existing_count INTEGER;
BEGIN
    -- Get Mathisle location ID
    SELECT locationid INTO loc_id FROM shared.locations WHERE locationname = 'Mathisle';
    
    IF loc_id IS NULL THEN
        RAISE EXCEPTION 'Mathisle location not found. Run 19-mathisle-seed-data.sql first.';
    END IF;

    -- Check if trees already exist for Mathisle (idempotent)
    SELECT COUNT(*) INTO existing_count FROM trees.trees WHERE locationid = loc_id;
    
    IF existing_count > 0 THEN
        RAISE NOTICE 'Mathisle trees already imported (% trees exist), skipping...', existing_count;
        RETURN;
    END IF;
    
    RAISE NOTICE 'Importing Mathisle trees to location ID %...', loc_id;

    -- Insert all trees

    GET DIAGNOSTICS existing_count = ROW_COUNT;
    RAISE NOTICE 'Imported % trees to Mathisle location', existing_count;
    
END $$;

-- Show import summary
DO $$
DECLARE
    tree_count INTEGER;
    loc_id INTEGER;
BEGIN
    SELECT locationid INTO loc_id FROM shared.locations WHERE locationname = 'Mathisle';
    SELECT COUNT(*) INTO tree_count FROM trees.trees WHERE locationid = loc_id;
    
    RAISE NOTICE '======================================================';
    RAISE NOTICE 'Mathisle Tree Import Complete';
    RAISE NOTICE 'Total trees: %', tree_count;
    RAISE NOTICE '======================================================';
END $$;

